import React from 'react'

type ButtonProps = {
  title: string
  onClick?: () => void
  variant?: 'primary' | 'secondary'
}

export default function Button({ title, onClick, variant = 'primary' }: ButtonProps) {
  return (
    <button
      onClick={onClick}
      style={{
        ...styles.base,
        ...(variant === 'primary' ? styles.primary : styles.secondary)
      }}
    >
      {title}
    </button>
  )
}

const styles = {
  base: {
    borderRadius: 8,
    paddingHorizontal: 18,
    paddingVertical: 12,
    fontSize: 16,
    fontWeight: 600,
    border: 'none',
    cursor: 'pointer'
  },
  primary: {
    backgroundColor: '#2563eb',
    color: '#ffffff'
  },
  secondary: {
    backgroundColor: '#475569',
    color: '#ffffff'
  }
}

